
























































































































































import { Component, Vue } from 'vue-property-decorator'
import axios from 'axios'

@Component
export default class Forms extends Vue {
  tableData= []
  currentPage = 1
  multipleSelection = []

  filters = {
    undergraduateSchool: '',
    department: '',
    intentionalCollegeCode: '',
    intentionalTutorName: '',
  }
  drawer = false

  details = {
    title: ''
  }

  getProjectList() {
    axios({
      url: '/formslist',
      data: {
        page: 1,
        pagination: 10
      }
    })
    .then((resp: any)=>{
      this.tableData = resp.data || []
    })
  }

  // 跳转到项目详情页
  projectDetail(index: number, scope: any){
    this.details.title = this.tableData[index]
    // 可能需要调用接口查询报名表详情，目前先使用表格中的数据
    this.drawer = true
  }
  // 修改报名表状态
  changeStatus(index: number, scope: any){
    console.log(scope, index)
  }

  pageChange(){
    console.log("sss", this.currentPage)
  }

  handleSizeChange(val: number) {
    console.log(`每页 ${val} 条`);
  }

  handleCurrentChange(val: number) {
    console.log(`当前页: ${val}`);
    this.currentPage = val
    this.getProjectList()
  }

  // 导出当前报名表
  exportCurrent() {
    console.log("exportCurrent")
  }

  // 批量导出已勾选报名表
  exportBatch() {
    console.log("exportBatch")
    // 调用后端接口，入参为已勾选报名表id列表
  }

  // 导出全部有权限的报名表
  exportAll() {
    console.log("exportAll")
    // 调用后端接口，入参为已勾选报名表id列表
  }

  // 处理多选
  handleSelectionChange(val: any) {
    this.multipleSelection = val;
    console.log("handleSelectionChange", val)
  }

  mounted(){
    this.getProjectList()
  }
}
